  ('promotion-53250add-moex-00058', 'promotion-53250add', 'promotion-53250add-moex-114-3082b5f1', 'sub-promotion-53250add-04', NULL, 'single_choice', '關於行政訴訟第一審裁判之敘述，下列何者正確？', '["法官非參與裁判基礎之辯論者，不得參與裁判", "各種獨立之攻擊或防禦方法，達於可為裁判之程度者，行政法院應為終局判決", "當事人兩造於言詞辯論期日，無正當理由均不到場者，行政法院不得逕為判決", "行政法院對於行政機關依裁量權所為之行政處分，均不得予以撤銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:45+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "137", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
